function OnMySettingsEdit(n){n.getElements();var e=n.oCont.appendChild(BX.create("SPAN",{html:n.oInput.value})),t=n.oCont.appendChild(BX.create("BUTTON",{html:n.data}));t.onclick=BX.delegate(function(){return BX.calendar({node:t,field:n.oInput,callback_after:function(){e.innerHTML=n.oInput.value}}),!1})}